module.exports = function(target, key, value) {
  var current, i, j, keys, ref;
  if (key == null) {
    return;
  }
  keys = key.split('__');
  if (keys.length === 1) {
    target[key] = value;
  } else {
    current = target;
    for (i = j = 0, ref = keys.length - 1; 0 <= ref ? j < ref : j > ref; i = 0 <= ref ? ++j : --j) {
      key = keys[i];
      current[key] = {};
      current = current[key];
    }
    key = keys[keys.length - 1];
    current[key] = value;
  }
};
